template.script:
            document.addEventListener('DOMContentLoaded', function () {
                // Initialize portal chatter manually
                setTimeout(function() {
                    var discussionEl = document.getElementById('discussion');
                    if (discussionEl) {
                        // Portal chatter should auto-initialize, but if it doesn't, 
                        // Odoo's portal chatter JavaScript will handle it based on data attributes
                        // The structure matches Odoo's expected format
                    }
                }, 100);

                // Handle View Timesheets button click
                document.querySelectorAll('.view-timesheets-btn').forEach(function(btn) {
                    btn.addEventListener('click', function() {
                        var taskId = parseInt(this.getAttribute('data-task-id'));
                        if (!taskId) {
                            alert('Task ID not found');
                            return;
                        }

                        // Show loading state
                        var container = document.getElementById('timesheetsContainer');
                        container.innerHTML = '

Loading timesheets...';

                        // Show modal
                        var modalEl = document.getElementById('timesheetsModal');
                        if (typeof $ !== 'undefined') {
                            $(modalEl).modal('show');
                        } else {
                            modalEl.classList.add('show');
                            modalEl.style.display = 'block';
                            modalEl.setAttribute('aria-hidden', 'false');
                            document.body.classList.add('modal-open');
                        }

                        // Fetch timesheet data
                        fetch('/my/progress_reports/timesheets/' + taskId, {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                            },
                            body: JSON.stringify({
                                jsonrpc: '2.0',
                                method: 'call',
                                params: {},
                                id: Math.floor(Math.random() * 1000000)
                            }),
                            credentials: 'same-origin'
                        })
                        .then(response => response.json())
                        .then(function(data) {
                            var result = data.result || data;
                            displayTimesheets(result);
                        })
                        .catch(function(error) {
                            console.error('Error fetching timesheets:', error);
                            container.innerHTML = '
Error loading timesheets. Please try again.';
                        });

                        function displayTimesheets(result) {
                            if (result.error) {
                                container.innerHTML = '
Error: ' + result.error + '';
                                return;
                            }

                            if (result.success) {
                                var html = '';

                                // Helper function to build timesheet table
                                function buildTimesheetTable(timesheets, summary, sectionTitle) {
                                    var sectionHtml = '';

                                    if (sectionTitle) {
                                        sectionHtml += '
' + sectionTitle + '';
                                    }

                                    sectionHtml += '';
                                    sectionHtml += '
DateEmployeeDescriptionNo of WorkersTime Spent';
                                    sectionHtml += '';

                                    if (!timesheets || timesheets.length === 0) {
                                        sectionHtml += '
No timesheets found for this task.';
                                    } else {
                                        timesheets.forEach(function(ts) {
                                            sectionHtml += '
';
                                            sectionHtml += '' + (ts.date || '') + '';
                                            sectionHtml += '' + (ts.employee || '') + '';
                                            sectionHtml += '' + (ts.description || '') + '';
                                            sectionHtml += '' + (ts.no_of_workers || 1) + '';
                                            sectionHtml += '' + (ts.time_spent_formatted || (ts.time_spent || 0).toFixed(2)) + '';
                                            sectionHtml += '';
                                        });
                                    }

                                    sectionHtml += '';

                                    // Add summary - match portal format exactly
                                    if (summary) {
                                        sectionHtml += '
';
                                        sectionHtml += '
';
                                        sectionHtml += '
';
                                        sectionHtml += '';
                                        sectionHtml += '
';
                                        sectionHtml += 'Total Time Spent: ';
                                        sectionHtml += '' + (summary.total_time_spent_formatted || (summary.total_time_spent || 0).toFixed(2)) + '';
                                        sectionHtml += '';

                                        if (summary.allocated_hours > 0) {
                                            sectionHtml += '
';
                                            sectionHtml += 'Time Remaining: ';
                                            var remainingClass = (summary.remaining_hours < 0) ? 'text-danger' : '';
                                            sectionHtml += '' + (summary.remaining_hours_formatted || (summary.remaining_hours || 0).toFixed(2)) + '';
                                            sectionHtml += '';
                                            sectionHtml += '
';
                                            sectionHtml += 'Time Spent (Days) ?: ';
                                            sectionHtml += '' + (summary.eff_days || 0) + ' / ' + (summary.alloc_days || 0) + ' days';
                                            sectionHtml += '';
                                        }

                                        sectionHtml += '';
                                        sectionHtml += '';
                                    }

                                    return sectionHtml;
                                }

                                // Display main task timesheets first (if exists)
                                if (result.main_task && result.main_task.task_name) {
                                    html += buildTimesheetTable(
                                        result.main_task.timesheets,
                                        result.main_task.summary,
                                        'Main Task: ' + result.main_task.task_name
                                    );
                                }

                                // Display subtask timesheets
                                if (result.subtask) {
                                    html += buildTimesheetTable(
                                        result.subtask.timesheets,
                                        result.subtask.summary,
                                        'Subtask: ' + result.subtask.task_name
                                    );
                                }

                                if (!html) {
                                    html = '
No timesheet data available.';
                                }

                                container.innerHTML = html;
                            } else {
                                container.innerHTML = '
No timesheet data available.';
                            }
                        }
                    });
                });

                // Handle timesheets modal close buttons
                document.addEventListener('click', function(e) {
                    if (e.target.classList.contains('close-timesheets-modal-btn') || e.target.closest('.close-timesheets-modal-btn')) {
                        var modal = document.getElementById('timesheetsModal');
                        if (modal) {
                            if (typeof $ !== 'undefined') {
                                $(modal).modal('hide');
                            } else {
                                modal.classList.remove('show');
                                modal.style.display = 'none';
                                modal.setAttribute('aria-hidden', 'true');
                                document.body.classList.remove('modal-open');
                            }
                        }
                    }
                });

                // Close timesheets modal when clicking backdrop
                var timesheetsModalEl = document.getElementById('timesheetsModal');
                if (timesheetsModalEl) {
                    timesheetsModalEl.addEventListener('click', function(e) {
                        if (e.target === this) {
                            if (typeof $ !== 'undefined') {
                                $(this).modal('hide');
                            } else {
                                this.classList.remove('show');
                                this.style.display = 'none';
                                this.setAttribute('aria-hidden', 'true');
                                document.body.classList.remove('modal-open');
                            }
                        }
                    });
                }

                // Override breadcrumb to show Home / Progress Report / Report Details
                const breadcrumb = document.querySelector('.o_portal_submenu.breadcrumb');
                if (breadcrumb) {
                    // Clear existing breadcrumb items
                    breadcrumb.innerHTML = '';
                    // Add home icon
                    const homeItem = document.createElement('li');
                    homeItem.className = 'breadcrumb-item';
                    homeItem.innerHTML = '';
                    breadcrumb.appendChild(homeItem);
                    // Add Progress Report link
                    const reportItem = document.createElement('li');
                    reportItem.className = 'breadcrumb-item';
                    reportItem.innerHTML = 'Progress Report';
                    breadcrumb.appendChild(reportItem);
                    // Add Report Details (active)
                    const detailsItem = document.createElement('li');
                    detailsItem.className = 'breadcrumb-item active';
                    detailsItem.setAttribute('aria-current', 'page');
                    detailsItem.textContent = 'Report Details';
                    breadcrumb.appendChild(detailsItem);
                }
            });

            document.addEventListener('DOMContentLoaded', function () {
                // Parse images data from JSON
                var imagesData = {};
                try {
                    var jsonData = JSON.parse(document.getElementById('reportImagesData').textContent);
                    jsonData.forEach(function(report, idx) {
                        imagesData[idx] = report.images || [];
                    });
                } catch(e) {
                    console.error('Error parsing images data:', e);
                    imagesData = {};
                }

                // Handle View Images button click
                document.querySelectorAll('.view-images-btn').forEach(function(btn) {
                    btn.addEventListener('click', function() {
                        var rowIndex = parseInt(this.getAttribute('data-row-index'));
                        var images = imagesData[rowIndex] || [];

                        console.log('Row index:', rowIndex);
                        console.log('Images data:', images);
                        console.log('All images data:', imagesData);

                        // Clear previous images
                        var container = document.getElementById('imagesContainer');
                        container.innerHTML = '';

                        if (!images || images.length === 0) {
                            container.innerHTML = '

No images available for this task.';
                        } else {
                            images.forEach(function(img, idx) {
                                console.log('Processing image', idx, img);

                                var colDiv = document.createElement('div');
                                colDiv.className = 'col-md-6 col-lg-4 mb-3';

                                var imgElement = document.createElement('img');
                                // Ensure image data is properly formatted
                                var imageSrc = 'data:' + (img.mimetype || 'image/jpeg') + ';base64,' + (img.image || '');
                                imgElement.src = imageSrc;
                                imgElement.className = 'img-fluid rounded';
                                imgElement.style.cursor = 'pointer';
                                imgElement.style.width = '100%';
                                imgElement.style.height = '250px';
                                imgElement.style.objectFit = 'cover';
                                imgElement.style.objectPosition = 'center';
                                imgElement.title = 'Click to view full size';

                                // Handle image load error
                                imgElement.onerror = function() {
                                    console.error('Failed to load image:', img);
                                    this.style.display = 'none';
                                };

                                // Make image clickable to view full size
                                imgElement.addEventListener('click', function() {
                                    var fullSizeModalEl = document.getElementById('fullSizeImageModal');
                                    if (!fullSizeModalEl) {
                                        fullSizeModalEl = createFullSizeModal();
                                    }
                                    var fullSizeImg = document.getElementById('fullSizeImage');
                                    if (fullSizeImg) {
                                        fullSizeImg.src = this.src;
                                        // Show modal using jQuery or manual method
                                        if (typeof $ !== 'undefined') {
                                            $(fullSizeModalEl).modal('show');
                                        } else {
                                            fullSizeModalEl.classList.add('show');
                                            fullSizeModalEl.style.display = 'block';
                                            fullSizeModalEl.setAttribute('aria-hidden', 'false');
                                            document.body.classList.add('modal-open');
                                        }
                                    }
                                });

                                colDiv.appendChild(imgElement);
                                container.appendChild(colDiv);
                            });
                        }

                        // Show modal using jQuery (Odoo compatible)
                        var modalEl = document.getElementById('imagesModal');
                        if (typeof $ !== 'undefined') {
                            $(modalEl).modal('show');
                        } else {
                            // Fallback: manual show using Bootstrap classes
                            modalEl.classList.add('show');
                            modalEl.style.display = 'block';
                            modalEl.setAttribute('aria-hidden', 'false');
                            document.body.classList.add('modal-open');
                            // Remove existing backdrop if any
                            var existingBackdrop = document.getElementById('modalBackdrop');
                            if (existingBackdrop) {
                                existingBackdrop.remove();
                            }
                            var backdrop = document.createElement('div');
                            backdrop.className = 'modal-backdrop fade show';
                            backdrop.id = 'modalBackdrop';
                            document.body.appendChild(backdrop);
                        }
                    });
                });

                // Handle modal close buttons
                function closeModal(modalEl) {
                    if (typeof $ !== 'undefined') {
                        $(modalEl).modal('hide');
                    } else {
                        // Manual close
                        modalEl.classList.remove('show');
                        modalEl.style.display = 'none';
                        modalEl.setAttribute('aria-hidden', 'true');
                        document.body.classList.remove('modal-open');
                        var backdrop = document.getElementById('modalBackdrop');
                        if (backdrop) {
                            backdrop.remove();
                        }
                    }
                }

                // Add close handlers to modal buttons
                document.addEventListener('click', function(e) {
                    if (e.target.classList.contains('close-modal-btn')) {
                        var modal = e.target.closest('.modal');
                        if (modal) {
                            closeModal(modal);
                        }
                    }
                });

                // Close modal when clicking backdrop
                var imagesModalEl = document.getElementById('imagesModal');
                if (imagesModalEl) {
                    imagesModalEl.addEventListener('click', function(e) {
                        if (e.target === this) {
                            closeModal(this);
                        }
                    });
                }

                // Create full size image modal if it doesn't exist
                function createFullSizeModal() {
                    var modalDiv = document.createElement('div');
                    modalDiv.className = 'modal fade';
                    modalDiv.id = 'fullSizeImageModal';
                    modalDiv.innerHTML = `














                    `;
                    document.body.appendChild(modalDiv);

                    // Add close handler for full size modal
                    modalDiv.querySelector('.close-fullsize-modal').addEventListener('click', function() {
                        closeModal(modalDiv);
                    });

                    // Close on backdrop click
                    modalDiv.addEventListener('click', function(e) {
                        if (e.target === modalDiv) {
                            closeModal(modalDiv);
                        }
                    });

                    return modalDiv;
                }
            });
